CREATE TABLE OrderHeader (
	CompanyCD		 VARCHAR2(5)	NOT NULL,
	RegisteredPerson	 VARCHAR2(20),
	RegisteredDT		 DATE,
	UpdatedPerson		 VARCHAR2(20),
	UpdatedDT		 DATE,
	ExclusiveFG		 CHAR(32),
	SlipNO			 VARCHAR2(15)	NOT NULL,
	CorporateNA_KANA	 VARCHAR2(40),
	CorporateNA		 VARCHAR2(40)
 );
CREATE UNIQUE INDEX AK_OrderHeader_1
 ON OrderHeader(
	CompanyCD,
	SlipNO
);

CREATE TABLE OrderDetail (
	CompanyCD		 VARCHAR2(5)	NOT NULL,
	RegisteredPerson	 VARCHAR2(20),
	RegisteredDT		 DATE,
	UpdatedPerson		 VARCHAR2(20),
	UpdatedDT		 DATE,
	ExclusiveFG		 CHAR(32),
	SlipNO			 VARCHAR2(15)	NOT NULL,
	DetailNo		NUMBER(3,0)	NOT NULL,
	ItemCD			 VARCHAR2(15)	NOT NULL,
	OrderQT			 NUMBER(6,0),
	UnitPrice		 NUMBER(15,3),
	OrderAT			 NUMBER(12,0),
	StockFG			 VARCHAR2(1),
	InspectionFG		 VARCHAR2(1),
	DeliveryDT		 DATE,
	Remark			 VARCHAR2(100),
	DetailID		 VARCHAR2(32)
 );
CREATE UNIQUE INDEX AK_OrderDetail_1
 ON OrderDetail(
	CompanyCD,
	SlipNO,
	DetailNo
);

CREATE TABLE SNumbering (
	CompanyCD		 VARCHAR2(5)	NOT NULL,
	RegisteredPerson	 VARCHAR2(20),
	RegisteredDT		 DATE,
	UpdatedPerson		 VARCHAR2(20),
	UpdatedDT		 DATE,
	ExclusiveFG		 CHAR(32),
	Code			 VARCHAR2(10)	NOT NULL,
	Name			 VARCHAR2(40),
	ConstValue		 VARCHAR2(10),
	StartValue		 NUMBER(8,0),
	EndValue		 NUMBER(8,0),
	IncrementValue		 NUMBER(8,0),
	CurrentValue		 NUMBER(8,0)
 );
CREATE UNIQUE INDEX AK_SNumbering_1
 ON SNumbering(
	CompanyCD,
	Code
);

CREATE TABLE ItemMaster (
	CompanyCD		 VARCHAR2(5)	NOT NULL,
	RegisteredPerson	 VARCHAR2(20),
	RegisteredDT		 DATE,
	UpdatedPerson		 VARCHAR2(20),
	UpdatedDT		 DATE,
	ExclusiveFG		 CHAR(32),
	StartDT			 DATE,
	InvalidDT		 DATE,
	ItemCD			 VARCHAR2(15)	NOT NULL,
	ItemNA			 VARCHAR2(50),
	ItemNA_KANA		 VARCHAR2(50),
	Standard		 VARCHAR2(20),
	Unit			 VARCHAR2(3),
	UnitPrice		 NUMBER(15,3),
	StockFG			 VARCHAR2(1),
	InspectionFG		VARCHAR2(1),
	StockQT			 NUMBER(6,0)
 );
CREATE UNIQUE INDEX AK_ItemMaster_1
 ON ItemMaster(
	CompanyCD,
	ItemCD
);

CREATE TABLE UnitMaster (
	CompanyCD		 VARCHAR2(5)	NOT NULL,
	RegisteredPerson	 VARCHAR2(20),
	RegisteredDT		 DATE,
	UpdatedPerson		 VARCHAR2(20),
	UpdatedDT		 DATE,
	ExclusiveFG		 CHAR(32),
	Code			 VARCHAR2(3)	NOT NULL,
	Name			 VARCHAR2(20)
 );
CREATE UNIQUE INDEX AK_UnitMaster_1
 ON UnitMaster(
	CompanyCD,
	Code
);




COMMIT;